import React, { useMemo, useState } from 'react';
import {
  Input,
  Modal,
  dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { masterService } from '../../../services/master/masterService';
import type { AssetLookupDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import {
  CatalogFormFooter,
  useCatalogPagination,
  useCatalogTableBusy,
  CatalogListHeaderFilters,
  CatalogListMasterLinPageLayout,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-ho-tro-tscd';

type FormErrors = Partial<Record<'code' | 'name', string>>;

type AssetLookupGridRow = Omit<AssetLookupDto, 'id'> & {
  id: string;
  lookupId: number;
};

const TABS = [
  { key: 'assetCategories', label: 'Loại TSCĐ', title: 'Loại tài sản cố định' },
  { key: 'capitalSources', label: 'Nguồn vốn', title: 'Nguồn vốn hình thành TSCĐ' },
  { key: 'increaseReasons', label: 'Lý do tăng', title: 'Lý do tăng TSCĐ' },
  { key: 'decreaseReasons', label: 'Lý do giảm', title: 'Lý do giảm TSCĐ' },
] as const;

type TabKey = typeof TABS[number]['key'];

const TAB_CATALOG_KIND: Record<TabKey, string> = {
  assetCategories: 'asset-categories',
  capitalSources: 'capital-sources',
  increaseReasons: 'increase-reasons',
  decreaseReasons: 'decrease-reasons',
};

const HoTroTscdPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [tab, setTab] = useState<TabKey>('assetCategories');
  const [items, setItems] = useState<AssetLookupDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<AssetLookupDto | null>(null);
  const [form, setForm] = useState<Partial<AssetLookupDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);

  const catalogKind = TAB_CATALOG_KIND[tab];
  const { schema, reload: reloadSchema } = useCatalogUiSchema(catalogKind);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);

  const tabMeta = TABS.find(t => t.key === tab)!;
  const { page, setPage, pageItems, totalCount, pageSize, setPageSize, resetPage } = useCatalogPagination(items);
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const gridRows = useMemo<AssetLookupGridRow[]>(
    () => pageItems.map(r => {
      const { id, ...rest } = r;
      return { ...rest, lookupId: id, id: String(id) };
    }),
    [pageItems],
  );

  const selection = useCatalogListSelection({
    rows: gridRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getAssetLookup(tab)
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải danh mục TSCĐ', type: 'error' });
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [tab, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã';
    if (!form.name?.trim()) next.name = 'Nhập tên';
    return next;
  };

  const closeFormModal = () => {
    setModalOpen(false);
    markClean();
  };

  const openAdd = () => {
    setEditing(null);
    setForm({ isActive: true });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openEdit = (row: AssetLookupGridRow) => {
    const { id: _gridId, lookupId, ...rest } = row;
    const dto: AssetLookupDto = { id: lookupId, ...rest };
    setEditing(dto);
    setForm({ ...dto });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateAssetLookup(tab, editing.id, form);
      else await masterService.createAssetLookup(tab, form);
      dispatchAppToast(dispatch, { message: editing ? 'Cập nhật thành công' : 'Tạo mới thành công', type: 'success' });
      markClean();
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const resolveDeleteIds = (): number[] => {
    if (selection.selectionMode === 'all') {
      return items.map(r => r.id);
    }
    return [...selection.selectedIds]
      .map(gridId => gridRows.find(r => r.id === gridId)?.lookupId)
      .filter((id): id is number => id != null);
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids = resolveDeleteIds();
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateAssetLookup(tab, id, { ...row, isActive: false });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} mục`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteAssetLookup(tab, id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} mục`, type: 'success' });
    }
    refresh();
  };

  const handleTabChange = (next: TabKey) => {
    setTab(next);
    resetPage();
    selection.clearSelection();
  };

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={catalogKind}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={gridRows}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setPage(p); selection.clearSelection(); }}
        onPageSizeChange={setPageSize}
        showTableLoading={showTableLoading}
        header={{ title: 'Hỗ trợ TSCĐ', titleIconClass: 'fas fa-landmark', subTitle: tabMeta.title }}
        listTitle={tabMeta.title}
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID}>
            {null}
          </CatalogListHeaderFilters>
        )}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={catalogKind}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => {
              reloadSchema();
              refresh();
            }}
          />
        )}
        topChrome={(
          <div className={styles.tabs}>
            {TABS.map(t => (
              <button
                key={t.key}
                type="button"
                className={tab === t.key ? styles.tabActive : styles.tab}
                onClick={() => handleTabChange(t.key)}
              >
                {t.label}
              </button>
            ))}
          </div>
        )}
        extraModals={<LeaveConfirmModal {...leaveConfirmModalProps} />}
      >
        {gridRows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={gridRows}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={() => true}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal isOpen={modalOpen} onClose={closeFormModal} title={editing ? `Sửa ${tabMeta.label}` : `Thêm ${tabMeta.label}`}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên *</label>
                <Input
                  value={form.name ?? ''}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
          </div>
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
          />
        </div>
      </Modal>
    </>
  );
};

export default HoTroTscdPage;
